import type { JSX } from 'react';

import { DatabaseIcon, MagnifyingGlassIcon } from '@dynatrace/strato-icons';

import type {
  ErrorRes,
  SuccessRes,
} from '../../../../../core/slots/Intent/Intent.js';
import { showToast } from '../../../../../notifications/toast/Toast.js';
import { ChartSeriesAction } from '../../series-action/ChartSeriesAction.js';
import { SeriesName } from '../types.js';

const TOASTER_LIFESPAN = 800;
const IS_ASYNC = true;
let toasterCounter = 0;

const seriesActions = (data: { name: SeriesName }) => {
  return (
    <ChartSeriesAction>
      <ChartSeriesAction.Item
        key="custom-action"
        onSelect={() => {
          showToast({
            title: `Inspecting ${data.name} ...`,
            type: 'info',
            lifespan: 1000,
          });
        }}
      >
        <ChartSeriesAction.ItemIcon>
          <MagnifyingGlassIcon />
        </ChartSeriesAction.ItemIcon>
        Inspect
      </ChartSeriesAction.Item>
      <ChartSeriesAction.Item
        disabled
        onSelect={() => void 0}
        key="disabled-action"
      >
        <ChartSeriesAction.ItemIcon>
          <DatabaseIcon />
        </ChartSeriesAction.ItemIcon>
        A disabled action
      </ChartSeriesAction.Item>
      <ChartSeriesAction.Intent
        options={{
          responseProperties: ['dt.share'],
        }}
        payload={{ 'dt.query': 'describe logs' }}
        onResponse={(response: SuccessRes | ErrorRes) => {
          if (response.status === 'success') {
            showToast({
              title: 'done...',
              type: 'info',
              lifespan: TOASTER_LIFESPAN,
            });
          } else {
            showToast({
              title: response.error.message,
              type: 'critical',
              lifespan: TOASTER_LIFESPAN,
            });
          }
        }}
      >
        Send intent with response
      </ChartSeriesAction.Intent>
    </ChartSeriesAction>
  );
};

export const asyncSeriesActions = (data: { name: SeriesName }) => {
  if (!IS_ASYNC) {
    return seriesActions(data);
  }

  return new Promise<JSX.Element>((resolve, reject) => {
    showToast({
      title: `Loading series actions ...: ${toasterCounter++}`,
      type: 'warning',
      lifespan: TOASTER_LIFESPAN,
    });
    setTimeout(() => {
      if (toasterCounter % 5 === 0) {
        showToast({
          title: `Failed to load series actions ...: ${toasterCounter++}`,
          type: 'critical',
          lifespan: TOASTER_LIFESPAN,
        });
        reject(new Error('Failed to load actions'));
      } else {
        resolve(seriesActions(data));
      }
    }, 500);
  });
};
